select

from device d
inner join product p on p.product_identification = d.product_identification
    and p.tenant_id = d.tenant_id
where d.client_id = #{clientId,jdbcType=VARCHAR}
  and d.product_identification = #{productIdentification,jdbcType=VARCHAR}
  and d.device_identification = #{deviceIdentification,jdbcType=VARCHAR}
  and d.device_status = #{deviceStatus,jdbcType=VARCHAR}
  and upper(p.protocol_type) = upper(#{protocolType,jdbcType=VARCHAR})
  and d.deleted = 0
limit 1

select

from device d
left join product p on p.product_identification = d.product_identification
    and p.tenant_id = d.tenant_id


        and d.client_id = #{clientId,jdbcType=VARCHAR}


        and p.user_name = #{userName,jdbcType=VARCHAR}


        and p.password = #{password,jdbcType=VARCHAR}


        and d.device_status = #{deviceStatus,jdbcType=VARCHAR}


        and p.protocol_type = #{protocolType,jdbcType=VARCHAR}

    and d.deleted = 0

limit 1

mapper.update:
update device
set connect_status = #{connectStatus,jdbcType=VARCHAR},
    last_online_time = case
        when #{connectStatus,jdbcType=VARCHAR} = 'ONLINE'
            then #{lastOnlineTime,jdbcType=TIMESTAMP}
        else last_online_time
    end,
    active_status = case
        when #{connectStatus,jdbcType=VARCHAR} = 'ONLINE' then 1
        else active_status
    end,
    activated_time = case
        when #{connectStatus,jdbcType=VARCHAR} = 'ONLINE'
            then COALESCE(activated_time, CURRENT_TIMESTAMP)
        else activated_time
    end,
    update_time = CURRENT_TIMESTAMP
where id = #{deviceId,jdbcType=BIGINT}
  and tenant_id = #{tenantId,jdbcType=BIGINT}
  and deleted = 0
